import{_ as t,c as d,o as s,a5 as r,j as a}from"./chunks/framework.Dtwt352Q.js";const _=JSON.parse('{"title":"v1.2.10：Sidecar 优化、SDK 构建改进","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.2.10.md","filePath":"changelog/v1.2.10.md","lastUpdated":1772014034000}'),o={name:"changelog/v1.2.10.md"};function l(i,e,n,h,c,p){return s(),d("div",null,[...e[0]||(e[0]=[r('<h1 id="v1-2-10-sidecar-优化、sdk-构建改进" tabindex="-1">v1.2.10：Sidecar 优化、SDK 构建改进 <a class="header-anchor" href="#v1-2-10-sidecar-优化、sdk-构建改进" aria-label="Permalink to “v1.2.10：Sidecar 优化、SDK 构建改进”">​</a></h1><p><strong>发布日期</strong>：2026-02-20</p><p>小版本更新，优化了桌面端 sidecar 的启动逻辑，并改进了 SDK 的构建输出。</p><h2 id="🎯-一句话总结" tabindex="-1">🎯 一句话总结 <a class="header-anchor" href="#🎯-一句话总结" aria-label="Permalink to “🎯 一句话总结”">​</a></h2><p>桌面端 sidecar 更智能（仅非 localhost 时启动）；SDK 构建目录优化。</p><hr><h2 id="✨-改进" tabindex="-1">✨ 改进 <a class="header-anchor" href="#✨-改进" aria-label="Permalink to “✨ 改进”">​</a></h2><h3 id="桌面端-sidecar-优化" tabindex="-1">桌面端 Sidecar 优化 <a class="header-anchor" href="#桌面端-sidecar-优化" aria-label="Permalink to “桌面端 Sidecar 优化”">​</a></h3><p>当默认服务器是 localhost 时，<strong>不再启动 sidecar 进程</strong>。</p><p><strong>收益</strong>：减少不必要的进程启动，节省资源。</p><p><strong>对谁有价值</strong>：使用本地服务器的桌面端用户。</p><hr><h3 id="sdk-构建目录优化" tabindex="-1">SDK 构建目录优化 <a class="header-anchor" href="#sdk-构建目录优化" aria-label="Permalink to “SDK 构建目录优化”">​</a></h3><p>SDK 现在构建到 <code>dist/</code> 目录，而不是 <code>dist/src/</code>。</p><p><strong>收益</strong>：更简洁的包结构，导入路径更直观。</p><p><strong>对谁有价值</strong>：使用 OpenCode SDK 的开发者。</p><hr><h2 id="📊-要不要升级" tabindex="-1">📊 要不要升级？ <a class="header-anchor" href="#📊-要不要升级" aria-label="Permalink to “📊 要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>开发 SDK</td><td>✅ 推荐</td></tr><tr><td>使用本地服务器</td><td>⚪ 可选升级</td></tr><tr><td>普通用户</td><td>⚪ 可选升级</td></tr></tbody></table><hr><h2 id="⬆️-升级命令" tabindex="-1">⬆️ 升级命令 <a class="header-anchor" href="#⬆️-升级命令" aria-label="Permalink to “⬆️ 升级命令”">​</a></h2>',21),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),r('<hr><h2 id="📚-文档更新" tabindex="-1">📚 文档更新 <a class="header-anchor" href="#📚-文档更新" aria-label="Permalink to “📚 文档更新”">​</a></h2><h3 id="自定义工具名冲突优先级" tabindex="-1">自定义工具名冲突优先级 <a class="header-anchor" href="#自定义工具名冲突优先级" aria-label="Permalink to “自定义工具名冲突优先级”">​</a></h3><p>官方文档新增了「工具名冲突」章节，明确了：</p><ul><li><strong>自定义工具会覆盖同名内置工具</strong></li><li>例如：创建 <code>.opencode/tool/bash.ts</code> 会替换内置的 <code>bash</code> 工具</li><li>如果想禁用内置工具而非覆盖，应使用 <a href="/5-advanced/05-permissions.html">权限配置</a></li></ul><p><strong>对谁有价值</strong>：需要定制或限制内置工具行为的高级用户。</p><hr><h2 id="📋-技术细节" tabindex="-1">📋 技术细节 <a class="header-anchor" href="#📋-技术细节" aria-label="Permalink to “📋 技术细节”">​</a></h2><details><summary>点击展开原始 Release Notes</summary><h2 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h2><ul><li>Don&#39;t spawn sidecar if default is localhost server</li></ul><h2 id="sdk" tabindex="-1">SDK <a class="header-anchor" href="#sdk" aria-label="Permalink to “SDK”">​</a></h2><ul><li>Build SDK to dist/ instead of dist/src</li></ul><p><strong>Thank you to 1 community contributor:</strong></p><ul><li>@rmk40: docs: clarify tool name collision precedence</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',11)])])}const m=t(o,[["render",l]]);export{_ as __pageData,m as default};
